  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum EducationLevel {\n  SECONDARY\n  HIGH_SCHOOL\n  DIPLOMA\n  BACHELOR\n  MASTER\n  DOCTORATE\n  OTHER\n}\n\nmodel User {\n  id       String @id @default(uuid())\n  username String\n  email    String @unique\n  password String\n  role     Role\n\n  fname          String?\n  lname          String?\n  birthDate      DateTime?\n  educationLevel EducationLevel?\n\n  createdAt DateTime @default(now())\n\n  enrollments     Enrollment[]\n  feedbacks       Feedback[]\n  certificates    Certificate[]\n  recommendations RecommendationLog[]\n  interests       UserInterest[]\n  interactions    UserInteraction[]\n}\n\nenum Role {\n  admin\n  student\n}\n\nmodel Course {\n  id String @id @default(uuid())\n\n  courseName        String\n  courseNameEn      String\n  courseDescription String\n\n  targetGroup  String?\n  organization String?\n  university   String?\n  price        Float?\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id])\n\n  level Level\n\n  thumbnailUrl String?\n\n  embedding CourseEmbedding?\n\n  createdAt DateTime @default(now())\n\n  modules      Module[]\n  keywords     CourseKeyword[]\n  enrollments  Enrollment[]\n  feedbacks    Feedback[]\n  certificates Certificate[]\n  interactions UserInteraction[]\n\n  slug String @unique @db.VarChar(255)\n\n  @@index([categoryId])\n}\n\nmodel Category {\n  id   String @id @default(uuid())\n  name String @unique\n\n  course Course[]\n}\n\nenum Level {\n  beginner\n  intermediate\n  advanced\n}\n\nmodel Instructor {\n  id   String @id @default(uuid())\n  name String\n\n  organization String?\n  title        String?\n\n  lessons Lesson[]\n}\n\n// ------ เก็บส่วนสำคัญของเนื้อหาภายในคอร์สไว้สำหรับ search, recommendations ------\nmodel CourseKeyword {\n  id       String @id @default(uuid())\n  courseId String\n  keyword  String\n\n  course Course @relation(fields: [courseId], references: [id])\n\n  @@unique([courseId, keyword])\n  @@index([courseId])\n}\n\nmodel Module {\n  id                String  @id @default(uuid())\n  courseId          String\n  moduleName        String\n  moduleDescription String?\n  durationMin       Int\n  orderIndex        Int\n\n  course  Course   @relation(fields: [courseId], references: [id])\n  lessons Lesson[]\n\n  @@index([courseId])\n}\n\nmodel Lesson {\n  id       String @id @default(uuid())\n  moduleId String\n\n  topicNo   String?\n  topicName String\n  videoUrl  String?\n\n  module Module @relation(fields: [moduleId], references: [id])\n\n  instructorId String?\n  instructor   Instructor? @relation(fields: [instructorId], references: [id])\n\n  performances LessonPerformance[]\n  tests        Test[]\n\n  @@index([moduleId])\n}\n\nmodel Enrollment {\n  id String @id @default(uuid())\n\n  userId   String\n  courseId String\n\n  status   EnrollmentStatus\n  progress Float            @default(0)\n\n  finalScore Float?\n\n  enrolledDate DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  user   User   @relation(fields: [userId], references: [id])\n  course Course @relation(fields: [courseId], references: [id])\n\n  performances LessonPerformance[]\n\n  @@unique([userId, courseId])\n  @@index([userId])\n  @@index([courseId])\n}\n\nenum EnrollmentStatus {\n  not_started\n  in_progress\n  completed\n}\n\nmodel LessonPerformance {\n  id           String       @id @default(uuid())\n  enrollmentId String\n  lessonId     String\n  quizScore    Float?\n  timeSpentMin Float?\n  lessonStatus LessonStatus\n\n  updatedAt DateTime @updatedAt\n\n  enrollment Enrollment @relation(fields: [enrollmentId], references: [id])\n  lesson     Lesson     @relation(fields: [lessonId], references: [id])\n\n  @@unique([enrollmentId, lessonId])\n  @@index([lessonId])\n}\n\nenum LessonStatus {\n  not_started\n  in_progress\n  completed\n}\n\nmodel Feedback {\n  id       String @id @default(uuid())\n  userId   String\n  courseId String\n\n  // ไม่ได้ fixed rating 1-5\n  rating  Int\n  comment String?\n\n  createdAt DateTime @default(now())\n\n  user   User   @relation(fields: [userId], references: [id])\n  course Course @relation(fields: [courseId], references: [id])\n\n  @@unique([userId, courseId])\n  @@index([courseId])\n}\n\n// ------ Test lesson ------ \nmodel Test {\n  id       String @id @default(uuid())\n  lessonId String\n\n  question String\n\n  optionA String\n  optionB String\n  optionC String\n  optionD String\n\n  correctAnswer String\n  score         Int\n\n  lesson Lesson @relation(fields: [lessonId], references: [id])\n\n  @@index([lessonId])\n}\n\nmodel RecommendationLog {\n  id                 String   @id @default(uuid())\n  userId             String\n  algorithm          String\n  generatedAt        DateTime @default(now())\n  recommendedCourses Json\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n}\n\nmodel Certificate {\n  id             String   @id @default(uuid())\n  certificateId  String   @unique\n  userId         String\n  courseId       String\n  issueDate      DateTime\n  certificateUrl String\n\n  user   User   @relation(fields: [userId], references: [id])\n  course Course @relation(fields: [courseId], references: [id])\n}\n\nmodel CourseEmbedding {\n  id        String                @id @default(uuid())\n  courseId  String                @unique\n  embedding Unsupported(\"vector\")\n\n  course Course @relation(fields: [courseId], references: [id])\n\n  @@index([courseId])\n}\n\nmodel UserInteraction {\n  id        String          @id @default(uuid())\n  userId    String\n  courseId  String\n  action    InteractionType\n  createdAt DateTime        @default(now())\n\n  user   User   @relation(fields: [userId], references: [id])\n  course Course @relation(fields: [courseId], references: [id])\n\n  @@index([userId])\n  @@index([courseId])\n}\n\nenum InteractionType {\n  view\n  click\n  enroll\n  complete\n  like\n  search\n}\n\nmodel UserInterest {\n  userId  String\n  keyword String\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@id([userId, keyword])\n  @@index([keyword])\n}\n",
